import time
import math
import numpy as np
from numba import njit, prange
from typing import Dict, Any, List

@njit(parallel=True, cache=True, fastmath=True)
def parallel_calculate_radiative_forcing(so2_injection_kg_s: np.ndarray, dispersion_winds_ms: np.ndarray, altitude_km: np.ndarray) -> np.ndarray:
    """Calculates the localized negative radiative forcing (Watts/m^2) generated by sulfur aerosol reflection."""
    total_fleets = so2_injection_kg_s.shape[0]
    radiative_cooling_w_m2 = np.zeros(total_fleets, dtype=np.float64)
    
    for i in prange(total_fleets):
        # Aerosols only effectively persist and reflect if injected above the tropopause (~18km near equator)
        if altitude_km[i] < 18.0:
            radiative_cooling_w_m2[i] = 0.0
            continue
            
        # Proxy calculation: SO2 converts to sulfate aerosols. Higher dispersion winds spread it thinner but wider.
        # Arbitrary scaling factor mapping kg/s to a W/m^2 cooling proxy over a standardized grid cell
        reflection_efficiency = 1.0 + (dispersion_winds_ms[i] * 0.05)
        cooling_effect = (so2_injection_kg_s[i] * reflection_efficiency) * 0.015 
        
        # Radiative forcing is negative (cooling)
        radiative_cooling_w_m2[i] = -cooling_effect
        
    return radiative_cooling_w_m2

class StratosphericGeoengineeringMatrix:
    def __init__(self):
        # Target cooling effect to negate localized global warming anomalies
        self.target_cooling_w_m2 = -2.5 

    def evaluate_albedo_modification(self, fleet_ids: List[str], operating_altitudes_km: List[float], injection_rates_kg_s: List[float], local_stratospheric_winds_ms: List[float]) -> dict:
        print(f"\n[GEOENGINEERING] Calculating global albedo modification via Stratospheric Aerosol Injection...")
        start_time = time.time()
        
        inj_arr = np.array(injection_rates_kg_s, dtype=np.float64)
        wind_arr = np.array(local_stratospheric_winds_ms, dtype=np.float64)
        alt_arr = np.array(operating_altitudes_km, dtype=np.float64)
        
        # Execute JIT Math
        cooling_effects = parallel_calculate_radiative_forcing(inj_arr, wind_arr, alt_arr)
        
        fleet_orders = []
        for i in range(len(fleet_ids)):
            cooling = cooling_effects[i]
            
            if operating_altitudes_km[i] < 18.0:
                fleet_orders.append({
                    "fleet_designation": fleet_ids[i],
                    "issue": "ALTITUDE_TOO_LOW_FOR_PERSISTENCE",
                    "action": "ABORT_INJECTION_CLIMB_TO_20KM"
                })
            elif cooling > self.target_cooling_w_m2: # Closer to 0 means not enough cooling
                fleet_orders.append({
                    "fleet_designation": fleet_ids[i],
                    "current_forcing_w_m2": round(cooling, 3),
                    "action": "INCREASE_SO2_PAYLOAD_DISPERSION"
                })
            else:
                fleet_orders.append({
                    "fleet_designation": fleet_ids[i],
                    "current_forcing_w_m2": round(cooling, 3),
                    "action": "OPTIMAL_ALBEDO_MAINTAIN_HEADING"
                })

        execution_ms = (time.time() - start_time) * 1000.0

        return {
            "planetary_albedo_status": "ACTIVE_MODIFICATION_ENGAGED",
            "drone_fleets_active": len(fleet_ids),
            "average_radiative_forcing_w_m2": round(np.mean(cooling_effects), 3),
            "fleet_directives": fleet_orders,
            "execution_time_ms": round(execution_ms, 5)
        }

if __name__ == "__main__":
    geo = StratosphericGeoengineeringMatrix()
    # Mocking high-altitude drone fleets. Fleet 1 is too low. Fleet 2 is perfectly cooling the upper atmosphere.
    print("TESTING STRATOSPHERIC GEOENGINEERING MATRIX:\n", geo.evaluate_albedo_modification(
        ["EQUATORIAL-FLEET-1", "ARCTIC-FLEET-2", "PACIFIC-FLEET-3"], 
        [15.0, 22.0, 20.0], # Altitudes
        [50.0, 120.0, 80.0], # Injection rate kg/s
        [10.0, 45.0, 25.0]   # Stratospheric winds m/s
    ))
